-- ----------------------------
-- Table structure for chat_session
-- ----------------------------
DROP TABLE IF EXISTS `chat_session`;
CREATE TABLE `chat_session`  (
  `session_id` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `owner_id` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `owner_type` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `title` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT '新会话',
  `turn_count` int NOT NULL DEFAULT 0,
  `active_turn_count` int NOT NULL DEFAULT 0,
  `retrieval_top_k` int NULL DEFAULT NULL COMMENT '会话级检索 top_k 覆盖值（为空则使用全局配置）',
  `similarity_threshold` double NULL DEFAULT NULL COMMENT '会话级相似度阈值覆盖值（0~1，空则使用全局配置）',
  `is_deleted` tinyint(1) NOT NULL DEFAULT 0,
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`session_id`) USING BTREE,
  INDEX `idx_chat_session_owner`(`owner_id` ASC, `owner_type` ASC) USING BTREE,
  INDEX `idx_chat_session_updated_at`(`updated_at` ASC) USING BTREE,
  INDEX `idx_chat_session_is_deleted`(`is_deleted` ASC) USING BTREE,
  INDEX `idx_chat_session_retrieval_top_k`(`retrieval_top_k` ASC) USING BTREE,
  INDEX `idx_chat_session_similarity_threshold`(`similarity_threshold` ASC) USING BTREE
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci ROW_FORMAT = Dynamic;

