-- ----------------------------
-- Table structure for chat_turn
-- ----------------------------
DROP TABLE IF EXISTS `chat_turn`;
CREATE TABLE `chat_turn`  (
  `turn_id` int NOT NULL AUTO_INCREMENT,
  `session_id` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `turn_no` int NOT NULL DEFAULT 1,
  `query` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `input_type` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'text',
  `ocr_text` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL,
  `answer` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `rewritten_query` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL,
  `sources` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `is_active` tinyint(1) NOT NULL DEFAULT 1,
  `tokens` int NOT NULL DEFAULT 0,
  `rating` tinyint NOT NULL DEFAULT 0,
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`turn_id`) USING BTREE,
  UNIQUE INDEX `uk_chat_turn_session_turn_no`(`session_id` ASC, `turn_no` ASC) USING BTREE,
  INDEX `idx_chat_turn_session_id`(`session_id` ASC) USING BTREE,
  INDEX `idx_chat_turn_is_active`(`is_active` ASC) USING BTREE,
  INDEX `idx_chat_turn_created_at`(`created_at` ASC) USING BTREE,
  INDEX `idx_chat_turn_input_type`(`input_type` ASC) USING BTREE,
  CONSTRAINT `fk_chat_turn_session` FOREIGN KEY (`session_id`) REFERENCES `chat_session` (`session_id`) ON DELETE RESTRICT ON UPDATE RESTRICT,
  CONSTRAINT `chat_turn_chk_1` CHECK (`rating` in (-(1),0,1))
) ENGINE = InnoDB AUTO_INCREMENT = 107 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci ROW_FORMAT = Dynamic;

