-- ----------------------------
-- Table structure for document
-- ----------------------------
DROP TABLE IF EXISTS `document`;
CREATE TABLE `document`  (
  `doc_id` bigint NOT NULL AUTO_INCREMENT COMMENT '文档主键ID',
  `kb_id` bigint NULL DEFAULT NULL COMMENT '所属知识库ID',
  `uploader_type` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '上传者类型: merchant 或 admin',
  `uploader_id` bigint NOT NULL COMMENT '上传者ID',
  `doc_name` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '文档名称',
  `doc_type` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '格式类型: pdf, docx, txt, md, csv',
  `doc_size` bigint NOT NULL COMMENT '文件大小 (字节)',
  `file_path` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '物理文件在本地的存储路径',
  `status` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT 'pending' COMMENT '状态: pending, processing, active, rejected',
  `chunk_size` int NULL DEFAULT NULL COMMENT '拆分块大小',
  `chunk_overlap` int NULL DEFAULT NULL COMMENT '拆分重叠度',
  `chunk_count` int NULL DEFAULT 0 COMMENT '拆分后的文本块数量',
  `created_at` datetime NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updated_at` datetime NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `is_deleted` varchar(1) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT 'F' COMMENT '逻辑删除标识: F-未删除, T-已删除',
  PRIMARY KEY (`doc_id`) USING BTREE,
  INDEX `fk_document_kb`(`kb_id` ASC) USING BTREE,
  CONSTRAINT `fk_document_kb` FOREIGN KEY (`kb_id`) REFERENCES `knowledge_base` (`kb_id`) ON DELETE SET NULL ON UPDATE RESTRICT
) ENGINE = InnoDB AUTO_INCREMENT = 47 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '文档实体表' ROW_FORMAT = Dynamic;

